// Code node: "Code in JavaScript" — SCIO Rate Generator v2
// Purpose: parse AI JSON, normalise categories, and output role rows with Google Sheets formulas.
// Requires workbook tabs: Rate_Card, Scarcity_Factors, Delivery_Context_Factors, Mobilisation_Factors, Client_Margins.
// Bakes in 35% margin protection by setting sell_point to at least buy_max_adjusted / (1 - 35%).

function tryParseJson(str) {
  if (typeof str !== "string") return null;
  try {
    const obj = JSON.parse(str);
    if (obj && typeof obj === "object") return obj;
  } catch {}
  return null;
}

function extractAgentJson(raw) {
  if (raw && typeof raw === "object" && Array.isArray(raw.roles)) return raw;

  const candidates = [];
  if (typeof raw === "string") candidates.push(raw);
  if (raw?.output) candidates.push(raw.output);
  if (raw?.text) candidates.push(raw.text);
  if (raw?.message) candidates.push(raw.message);
  if (raw?.json) candidates.push(raw.json);
  if (raw?.data) candidates.push(raw.data);
  if (raw?.choices) raw.choices.forEach(c => candidates.push(c?.message?.content || ""));

  for (const c of candidates) {
    const parsed = tryParseJson(c);
    if (parsed?.roles) return parsed;
  }

  throw new Error("Could not parse AI Agent output. Expected JSON object with roles[].");
}

function normOne(value, allowed, fallback) {
  if (value == null || value === "") return fallback || "";

  const s = String(value).trim().toLowerCase();

  for (const a of allowed) {
    if (s === a.toLowerCase()) return a;
  }

  // Forgiving aliases
  if (allowed.includes("Leader") && /leader|lead|principal|director/.test(s)) return "Leader";
  if (allowed.includes("Senior") && /senior|expert/.test(s)) return "Senior";
  if (allowed.includes("Intermediate") && /intermediate|mid|consultant/.test(s)) return "Intermediate";
  if (allowed.includes("Junior") && /junior|assistant|support/.test(s)) return "Junior";

  if (allowed.includes("High-risk") && /high.?risk|hardship|fragile|conflict|security/.test(s)) return "High-risk";
  if (allowed.includes("Complex") && /complex|travel|political|multi|stakeholder/.test(s)) return "Complex";

  if (allowed.includes("Immediate") && /immediate|emergency|urgent/.test(s)) return "Immediate";
  if (allowed.includes("Fast") && /fast|rapid|compressed|short/.test(s)) return "Fast";

  if (allowed.includes("Niche") && /niche|rare|very scarce/.test(s)) return "Niche";
  if (allowed.includes("Specialist") && /special|scarce|specific/.test(s)) return "Specialist";

  if (allowed.includes("Private") && /private|corporate|company/.test(s)) return "Private";
  if (allowed.includes("Foundation") && /foundation|philanth/.test(s)) return "Foundation";
  if (allowed.includes("Donor") && /donor|giz|un|eu|ingo|bilateral|multilateral/.test(s)) return "Donor";
  if (allowed.includes("Public") && /public|government|ministry|municipal/.test(s)) return "Public";

  return fallback || "";
}

function joinList(v) {
  if (Array.isArray(v)) return v.filter(Boolean).join(", ");
  return v || "";
}

function joinEvidence(v) {
  if (Array.isArray(v)) return v.filter(Boolean).join(" | ");
  return v || "";
}

const proj = extractAgentJson($json);
const roles = Array.isArray(proj.roles) ? proj.roles : [];

if (!roles.length) {
  throw new Error("No roles[] found in AI output.");
}

const projectDelivery = normOne(
  proj.delivery_context,
  ["Standard", "Complex", "High-risk"],
  "Standard"
);

const projectMobilisation = normOne(
  proj.mobilisation_speed,
  ["Standard", "Fast", "Immediate"],
  "Standard"
);

const clientType = normOne(
  proj.client_type,
  ["Public", "Donor", "Foundation", "Private"],
  "Donor"
);

function f(expr) {
  return "=" + expr;
}

// Column assumptions in generated team sheet:
// A project_id
// B project_name
// C client_name
// D client_type
// E country
// F file_name
// G role_id
// H role_title
// I skill_area
// J languages_required
// K role_days
// L years_experience_required
// M role_level
// N scarcity_level
// O delivery_context
// P mobilisation_speed
// Q classification_confidence
// R classification_rationale
// S evidence_quotes
// T buy_min_base
// U buy_point_base
// V buy_max_base
// W scarcity_factor
// X delivery_factor
// Y mobilisation_factor
// Z target_margin
// AA margin_floor
// AB margin_used
// AC buy_min_adjusted
// AD buy_point_adjusted
// AE buy_max_adjusted
// AF sell_min
// AG sell_point
// AH sell_max
// AI commercial_override_pct
// AJ final_sell_point
// AK gross_margin_point
// AL gross_margin_worst_case
// AM margin_status
// AN required_sell_for_35pct
// AO sell_gap_to_35pct
// AP review_required
// AQ approval_status
// AR approved_by
// AS review_notes

const formulas = {
  buy_min_base: f('IF(INDEX($M:$M,ROW())="","",INDEX(Rate_Card!$B:$B,MATCH(INDEX($M:$M,ROW()),Rate_Card!$A:$A,0)))'),
  buy_point_base: f('IF(INDEX($M:$M,ROW())="","",INDEX(Rate_Card!$C:$C,MATCH(INDEX($M:$M,ROW()),Rate_Card!$A:$A,0)))'),
  buy_max_base: f('IF(INDEX($M:$M,ROW())="","",INDEX(Rate_Card!$D:$D,MATCH(INDEX($M:$M,ROW()),Rate_Card!$A:$A,0)))'),

  scarcity_factor: f('IF(INDEX($N:$N,ROW())="","",INDEX(Scarcity_Factors!$B:$B,MATCH(INDEX($N:$N,ROW()),Scarcity_Factors!$A:$A,0)))'),
  delivery_factor: f('IF(INDEX($O:$O,ROW())="","",INDEX(Delivery_Context_Factors!$B:$B,MATCH(INDEX($O:$O,ROW()),Delivery_Context_Factors!$A:$A,0)))'),
  mobilisation_factor: f('IF(INDEX($P:$P,ROW())="","",INDEX(Mobilisation_Factors!$B:$B,MATCH(INDEX($P:$P,ROW()),Mobilisation_Factors!$A:$A,0)))'),

  target_margin: f('IF(INDEX($D:$D,ROW())="","",INDEX(Client_Margins!$B:$B,MATCH(INDEX($D:$D,ROW()),Client_Margins!$A:$A,0)))'),
  margin_floor: f('IF(INDEX($D:$D,ROW())="","",INDEX(Client_Margins!$C:$C,MATCH(INDEX($D:$D,ROW()),Client_Margins!$A:$A,0)))'),
  margin_used: f('IF(INDEX($D:$D,ROW())="","",MAX(INDEX($Z:$Z,ROW()),INDEX($AA:$AA,ROW())))'),

  buy_min_adjusted: f('IFERROR(INDEX($T:$T,ROW())*INDEX($W:$W,ROW())*INDEX($X:$X,ROW())*INDEX($Y:$Y,ROW()),"")'),
  buy_point_adjusted: f('IFERROR(INDEX($U:$U,ROW())*INDEX($W:$W,ROW())*INDEX($X:$X,ROW())*INDEX($Y:$Y,ROW()),"")'),
  buy_max_adjusted: f('IFERROR(INDEX($V:$V,ROW())*INDEX($W:$W,ROW())*INDEX($X:$X,ROW())*INDEX($Y:$Y,ROW()),"")'),

  sell_min: f('IFERROR(INDEX($AC:$AC,ROW())/(1-INDEX($AB:$AB,ROW())),"")'),

  // 35% margin protection:
  // sell_point must cover the point buy rate at the used margin
  // AND must cover the worst-case adjusted max buy rate at 35%.
  sell_point: f('IFERROR(MAX(INDEX($AD:$AD,ROW())/(1-INDEX($AB:$AB,ROW())),INDEX($AE:$AE,ROW())/(1-0.35)),"")'),

  sell_max: f('IFERROR(MAX(INDEX($AE:$AE,ROW())/(1-INDEX($AB:$AB,ROW())),INDEX($AG:$AG,ROW())),"")'),

  commercial_override_pct: 0,

  final_sell_point: f('IFERROR(INDEX($AG:$AG,ROW())*(1+INDEX($AI:$AI,ROW())),"")'),

  gross_margin_point: f('IFERROR((INDEX($AJ:$AJ,ROW())-INDEX($AD:$AD,ROW()))/INDEX($AJ:$AJ,ROW()),"")'),

  gross_margin_worst_case: f('IFERROR((INDEX($AJ:$AJ,ROW())-INDEX($AE:$AE,ROW()))/INDEX($AJ:$AJ,ROW()),"")'),

  margin_status: f('IF(INDEX($AJ:$AJ,ROW())="","",IF(INDEX($AL:$AL,ROW())>=0.35,"OK ≥35%","Below 35% floor"))'),

  required_sell_for_35pct: f('IFERROR(INDEX($AE:$AE,ROW())/(1-0.35),"")'),

  sell_gap_to_35pct: f('IFERROR(MAX(0,INDEX($AN:$AN,ROW())-INDEX($AJ:$AJ,ROW())),"")'),

  review_required: f('IF(OR(INDEX($M:$M,ROW())="Leader",INDEX($Q:$Q,ROW())="Low",INDEX($N:$N,ROW())="Niche",INDEX($O:$O,ROW())="High-risk",INDEX($P:$P,ROW())="Immediate",INDEX($AI:$AI,ROW())<>0,INDEX($AM:$AM,ROW())="Below 35% floor"),"Yes","No")'),

  approval_status: "Pending"
};

return roles.map((r, i) => {
  const roleLevel = normOne(
    r.role_level,
    ["Junior", "Intermediate", "Senior", "Leader"],
    ""
  );

  const scarcity = normOne(
    r.scarcity_level,
    ["Standard", "Specialist", "Niche"],
    "Standard"
  );

  const confidence = normOne(
    r.classification_confidence,
    ["High", "Medium", "Low"],
    "Medium"
  );

  return {
    json: {
      project_id: proj.project_id || null,
      project_name: proj.project_name || null,
      client_name: proj.client_name_raw || null,
      client_type: clientType,
      country: proj.country || null,
      file_name: proj.file_name || null,

      role_id: r.role_id || `R${i + 1}`,
      role_title: r.role_title || null,
      skill_area: r.skill_area || null,
      languages_required: joinList(r.languages_required),
      role_days: r.role_days ?? null,
      years_experience_required: r.years_experience_required ?? null,

      role_level: roleLevel,
      scarcity_level: scarcity,
      delivery_context: normOne(
        r.delivery_context || proj.delivery_context,
        ["Standard", "Complex", "High-risk"],
        projectDelivery
      ),
      mobilisation_speed: normOne(
        r.mobilisation_speed || proj.mobilisation_speed,
        ["Standard", "Fast", "Immediate"],
        projectMobilisation
      ),
      classification_confidence: confidence,
      classification_rationale: r.classification_rationale || null,
      evidence_quotes: joinEvidence(r.evidence_quotes),

      ...formulas,

      approved_by: "",
      review_notes: ""
    }
  };
});

